args.sparql:
SELECT ?film ?filmLabel (COUNT(?award) AS ?totalAwards)
WHERE {
  ?film wdt:P31 wd:Q11424;
        wdt:P57 wd:Q43203;
        rdfs:label ?filmLabel.
  FILTER (LANGMATCHES(LANG(?filmLabel), "en"))
  ?film wdt:P161 ?award.
  ?award wdt:P31 ?awardType.
  FILTER (?awardType = wd:Q35299 || ?awardType = wd:Q82198)
}
GROUP BY ?film ?filmLabel
ORDER BY DESC(?totalAwards)
LIMIT 1

